# --- Lookup helpers (used by Publisher post-step and LLM prompt builder) ---

_LOCAL_RE = re.compile(r"\b(\d{3,4})\b")


def _norm(s: str | None) -> str:
    return re.sub(r"\s+", " ", (s or "").strip()).lower()


def funds_for_union(local: str | int) -> list[dict]:
    """Return funds relevant to a given union local: union-specific
    (F<local>NNN) + shared national (F000NNN)."""
    local_str = str(local)
    out = []
    for f in FUNDS:
        fid = f.get("ID") or ""
        if fid.startswith("F000"):
            out.append(f)
        elif local_str in fid:
            out.append(f)
    return out


def packages_all() -> list[dict]:
    """Every master package — matching is by name within the union's
    naming family."""
    return list(PACKAGES)


def zones_for_union(local: str | int) -> list[dict]:
    """Zones whose Union column is the union’s formal name OR ‘All’."""
    local_str = str(local)
    out = []
    for z in ZONES:
        u = z.get("Union") or ""
        if u == "All":
            out.append(z)
        elif local_str in u:
            out.append(z)
    return out


def match_fund(local: str | int, extracted_name: str) -> tuple[dict | None, str]:
    """Match an extracted fund column header to a Master Fund List row.

    Returns (row, status) where status is one of:
      "OK"               exact name match
      "DRIFT"            near-match (case/space/punctuation drift)
      "NOT_FOUND"        nothing matches
    """
    if not extracted_name:
        return None, "NOT_FOUND"
    candidates = funds_for_union(local)
    target = _norm(extracted_name)
    for row in candidates:
        if _norm(row.get("Fund Name")) == target:
            return row, "OK"
    # Drift: same after stripping local-number suffix
    target_no_local = _norm(re.sub(r"\b\d{3,4}\b", "", extracted_name))
    for row in candidates:
        ref = _norm(re.sub(r"\b\d{3,4}\b", "", row.get("Fund Name") or ""))
        if ref == target_no_local and ref:
            return row, "DRIFT"
    # Hyphen / underscore drift
    target_alpha = re.sub(r"[^a-z0-9]", "", target)
    for row in candidates:
        ref = re.sub(r"[^a-z0-9]", "", _norm(row.get("Fund Name")))
        if ref == target_alpha and ref:
            return row, "DRIFT"
    return None, "NOT_FOUND"


def match_package(extracted_name: str) -> tuple[dict | None, str]:
    """Match an extracted package name to a Master Package List row."""
    if not extracted_name:
        return None, "NOT_FOUND"
    target = _norm(extracted_name)
    for row in PACKAGES:
        if _norm(row.get("Package Name")) == target:
            return row, "OK"
    target_alpha = re.sub(r"[^a-z0-9]", "", target)
    for row in PACKAGES:
        ref = re.sub(r"[^a-z0-9]", "", _norm(row.get("Package Name")))
        if ref == target_alpha and ref:
            return row, "DRIFT"
    return None, "NOT_FOUND"


def match_zone(local: str | int, extracted_name: str) -> tuple[dict | None, str]:
    """Match an extracted zone name to a Master Zone List row."""
    if not extracted_name:
        return None, "NOT_FOUND"
    candidates = zones_for_union(local)
    target = _norm(extracted_name)
    for row in candidates:
        if _norm(row.get("Zone Name")) == target:
            return row, "OK"
    target_alpha = re.sub(r"[^a-z0-9]", "", target)
    for row in candidates:
        ref = re.sub(r"[^a-z0-9]", "", _norm(row.get("Zone Name")))
        if ref == target_alpha and ref:
            return row, "DRIFT"
    return None, "NOT_FOUND"
